require "config.GiftBagConfig"

GiftBagController = class()

function GiftBagController:ctor(player)
    self.userId = player.userId
    self.giftBags = {}
    self.shownGiftBags = {}
    self.boughtGiftBags = {}
    self.isFirst = true
end

function GiftBagController:init()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local todayKey = DateUtil.getYearDay()
    if todayKey ~= player.gift_bag_day_key then
        player.gift_bag_day_key = 0
    end
    self:initGiftBags()
    self:initRefreshInfo()
    self:initShownGiftBags()
    self.isFirst = false
end

function GiftBagController:initGiftBags()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    self.giftBags = GiftBagConfig:getGiftBags()
    if next(player.bought_gift_bag) ~= nil then
        for _, id in pairs(player.bought_gift_bag) do
            self.giftBags[id].status = GiftBagConfig.GiftStatus.BOUGHT
            table.insert(self.boughtGiftBags, id)
        end
    end

    if next(player.gift_bags) ~= nil then
        for _, item in pairs(player.gift_bags) do
            self.giftBags[item.Id].status = item.Status
        end
    end
end

function GiftBagController:initRefreshInfo()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    local time = player.gift_bag_refresh_time - os.time()
    if time <= 0 then
        time = 0
    end
    GamePacketSender:sendPixelGunGiftBagRefreshTime(player.rakssid, time * 1000)
end

function GiftBagController:ifCanRefresh()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    local time = player.gift_bag_refresh_time - os.time()
    if time <= 0 then
        return true
    end
    return false
end

function GiftBagController:initShownGiftBags()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if self:ifCanRefresh() == true or next(player.gift_bags) == nil then
        self:refreshGiftBags()
        return
    end

    local gifts = player.gift_bags
    self.shownGiftBags = {}
    for _, item in pairs(gifts) do
        local gift = GiftBagConfig:getGiftBagById(item.Id)
        if gift ~= nil then
            gift.status = item.Status
            self.shownGiftBags[gift.id] = gift
        end
    end

    self:sendRefreshPixelGunGiftData()
end

function GiftBagController:getTableLength(Table)
    local table_item = Table
    local index = 0
    for k, v in pairs(table_item) do
        index = index + 1
    end
    return index
end

function GiftBagController:resetRefreshTime()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    local time = os.time() + GameMatch.refreshTime
    player.gift_bag_refresh_time = time
    GamePacketSender:sendPixelGunGiftBagRefreshTime(player.rakssid, (time - os.time()) * 1000)
end

function GiftBagController:refreshGiftBags()
    local new_gift = GiftBagConfig:getNewGifts()
    local num = 4
    self.shownGiftBags = {}
    if next(new_gift) ~= nil then
        for _, item in pairs(new_gift) do
            if self.giftBags[item.id].status ~= GiftBagConfig.GiftStatus.BOUGHT then
                local gift = {}
                GiftBagConfig:copy(item, gift)
                self.shownGiftBags[item.id] = gift
                num = num - 1
                if num == 0 then
                    break
                end
            end
        end
    end

    if num ~= 0 then
        local random_gifts = self:randomGiftBags(num)
        if next(random_gifts) ~= nil then
            for _, id in pairs(random_gifts) do
                local item = self.giftBags[id]
                if item ~= nil then
                    local gift = {}
                    GiftBagConfig:copy(item, gift)
                    self.shownGiftBags[item.id] = gift
                end
            end
        end
    end

    if self:ifCanRefresh() == true then
        self:resetRefreshTime()
    end
    self:sendRefreshPixelGunGiftData()
end

function GiftBagController:randomGiftBags(num)
    if num == 0 then
        return nil
    end
    local result = {}
    local pool = {}
    for _, item in pairs(self.giftBags) do
        if item.status ~= GiftBagConfig.GiftStatus.BOUGHT and item.type ~= GiftBagConfig.GiftType.NEW then
            table.insert(pool, item)
        end
    end

    local tableNum = self:getTableLength(pool)
    if tableNum < num then
        num = tableNum
    end

    for i = 1, num do
        local rs = math.random(0, self:getSumOfWeight(pool))
        for index, gift in pairs(pool) do
            rs = rs - gift.weight
            if rs < 0 then
                table.insert(result, gift.id)
                table.remove(pool, index)
                break
            end
        end
    end
    return result
end

function GiftBagController:getSumOfWeight(gifts)
    local sumOfWeight = 0
    for _, gift in pairs(gifts) do
        sumOfWeight = sumOfWeight + gift.weight
    end
    return sumOfWeight
end

function GiftBagController:getShownGiftById(giftId)
    for _, gift in pairs(self.shownGiftBags) do
        if gift.id == giftId then
            return gift
        end
    end
    return nil
end

function GiftBagController:sendRefreshPixelGunGiftData()
    local data = {}
    local player = PlayerManager:getPlayerByUserId(self.userId)
    local show = false
    if player.gift_bag_day_key == 0 then
        show = true
        player.gift_bag_day_key = DateUtil.getYearDay()
    end
    player.gift_bags = {}
    for _, gift in pairs(self.shownGiftBags) do
        local item = {}
        item.Id = gift.id
        item.Status = gift.status
        table.insert(data, item)
        table.insert(player.gift_bags, item)
    end
    GamePacketSender:sendPixelGunGiftBagData(player.rakssid, show, true, json.encode(data))

end

function GiftBagController:sendUpdatePixelGunGiftBagData(giftId)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local data = {}
    for _, gift in pairs(self.shownGiftBags) do
        if gift.id == giftId then
            local item = {}
            item.Id = gift.id
            item.Status = gift.status
            table.insert(data, item)
            self:updataPixelGunGiftBagData(gift)
            break
        end
    end
    if next(data) ~= nil then
        GamePacketSender:sendPixelGunGiftBagData(player.rakssid, false, false, json.encode(data))
    end
end

function GiftBagController:updataPixelGunGiftBagData(gift)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    for _, item in pairs(player.gift_bags) do
        if item.Id == gift.id then
            item.Status = gift.status
        end
    end
end

function GiftBagController:onGiftBagBought(giftId)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    local gift = self:getShownGiftById(giftId)
    if gift == nil then
        return
    end

    for _,id in pairs(gift.items) do
        local reward = RewardConfig:getRewardById(tonumber(id))
        GameReward:onPlayerGetReward(player, reward)
    end

    self.shownGiftBags[giftId].status = GiftBagConfig.GiftStatus.BOUGHT

    self:sendUpdatePixelGunGiftBagData(giftId)
    GamePacketSender:sendPixelGunRewardsResult(player.rakssid, gift.items)
    if gift.canRepeat == false then
        self.giftBags[giftId].status = GiftBagConfig.GiftStatus.BOUGHT
        table.insert(self.boughtGiftBags, gift.id)
        player.bought_gift_bag = self.boughtGiftBags
    end
end

return GiftBagController